import SwiftUI

struct AdaptivePopoverView: View {
    @State private var showPopover = false
    @State private var popoverSourceRect: CGRect = .zero

    var body: some View {
        VStack {
            Text("Tap for Popover")
                .padding()
                .background(GeometryReader { geo in
                    Color.clear.onAppear {
                        self.popoverSourceRect = geo.frame(in: .global)
                    }
                })
                .onTapGesture {
                    showPopover = true
                }
        }
        .adaptivePopover(isPresented: $showPopover, sourceRect: popoverSourceRect) {
            Text("This is a popover!")
                .padding()
        }
    }
}

