    init(note: String) {
        self.note = note
    }

    init() {}

    func perform() async throws -> some IntentResult {
        // Logic to update the widget's timeline with the new note
        WidgetCenter.shared.reloadTimelines(ofKind: "NoteWidget")
        return .result()
    }
}

